// ── Feign Client: declares HTTP interface as Java interface ────────
import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.*;

@FeignClient(name = "user-service") // name matches Eureka registration
interface UserServiceClient {
    @GetMapping("/api/users/{id}")
    UserDto getUser(@PathVariable Long id);

    @GetMapping("/api/users/{id}/xp")
    int getUserXp(@PathVariable Long id);
}

// ── Service using Feign + Circuit Breaker ─────────────────────────
import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.retry.annotation.Retry;
import org.springframework.stereotype.Service;

@Service
public class TopicProgressService {
    private final UserServiceClient userClient;

    public TopicProgressService(UserServiceClient userClient) {
        this.userClient = userClient;
    }

    @CircuitBreaker(name = "userService", fallbackMethod = "getXpFallback")
    @Retry(name = "userService") // retry 3 times before circuit counts failure
    public int getUserXpWithFallback(Long userId) {
        return userClient.getUserXp(userId); // HTTP call to user-service
    }

    // Fallback: called when circuit is OPEN or call fails after retries
    public int getXpFallback(Long userId, Exception ex) {
        System.out.println("Fallback for user " + userId + ": " + ex.getMessage());
        return 0; // safe default — show 0 XP instead of error page
    }
}

