// ── JWT Auth Filter (global) ──────────────────────────────────────
import org.springframework.cloud.gateway.filter.GatewayFilterChain;
import org.springframework.cloud.gateway.filter.GlobalFilter;
import org.springframework.core.Ordered;
import org.springframework.http.HttpStatus;
import org.springframework.stereotype.Component;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

@Component
public class JwtAuthGatewayFilter implements GlobalFilter, Ordered {

    @Override
    public Mono<Void> filter(ServerWebExchange exchange, GatewayFilterChain chain) {
        String path = exchange.getRequest().getPath().value();

        // Public paths — skip auth
        if (path.startsWith("/api/auth/")) {
            return chain.filter(exchange);
        }

        String authHeader = exchange.getRequest().getHeaders().getFirst("Authorization");
        if (authHeader == null || !authHeader.startsWith("Bearer ")) {
            exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
            return exchange.getResponse().setComplete();
        }

        String token = authHeader.substring(7);
        // Validate token (call auth-service or validate locally)
        if (!isValidToken(token)) {
            exchange.getResponse().setStatusCode(HttpStatus.UNAUTHORIZED);
            return exchange.getResponse().setComplete();
        }

        // Add user info to downstream headers
        String userId = extractUserId(token);
        ServerWebExchange modified = exchange.mutate()
            .request(r -> r.header("X-User-Id", userId))
            .build();
        return chain.filter(modified);
    }

    private boolean isValidToken(String token) { return token.length() > 10; /* stub */ }
    private String extractUserId(String token) { return "user-123"; /* stub */ }

    @Override
    public int getOrder() { return -1; } // run before routing
}

problems.description:
Implement the Circuit Breaker pattern using Resilience4j.

```java
@Service
public class PaymentService {
    @CircuitBreaker(name = "payment", fallbackMethod = "paymentFallback")
    @Retry(name = "payment", fallbackMethod = "paymentFallback")
    public PaymentResponse processPayment(PaymentRequest req) {
        return restTemplate.postForObject(PAYMENT_URL, req, PaymentResponse.class);
    }
    public PaymentResponse paymentFallback(PaymentRequest req, Exception e) {
        return PaymentResponse.queued("Payment queued for retry");
    }
}
```

**application.yml:**
```yaml
resilience4j.circuitbreaker.instances.payment:
  slidingWindowSize: 10
  failureRateThreshold: 50    # open if 50%+ failures
  waitDurationInOpenState: 5s  # try again after 5s
```

**States:** CLOSED (normal) → OPEN (failing, reject fast) → HALF_OPEN (test 1 request) → CLOSED (if OK)

**Key insight:** Fail fast prevents cascade failures. Fallback returns degraded but valid response. Retry + circuit breaker = complementary patterns.

