import java.util.function.Supplier;

public class Q1 {
    enum State { CLOSED, OPEN, HALF_OPEN }

    static class CircuitBreaker {
        private State state = State.CLOSED;
        private int failureCount = 0;
        private long openedAt = 0;
        private final int threshold = 3;
        private final long resetMs = 5000;

        public <T> T execute(Supplier<T> action) {
            if (state == State.OPEN) {
                if (System.currentTimeMillis() - openedAt > resetMs) {
                    state = State.HALF_OPEN;
                } else {
                    throw new CircuitOpenException();
                }
            }
            try {
                T result = action.get();
                if (state == State.HALF_OPEN) {
                    state = State.CLOSED; // probe succeeded
                    failureCount = 0;
                }
                failureCount = 0;
                return result;
            } catch (CircuitOpenException e) {
                throw e;
            } catch (Exception e) {
                failureCount++;
                if (state == State.HALF_OPEN || failureCount >= threshold) {
                    state = State.OPEN;
                    openedAt = System.currentTimeMillis();
                    failureCount = 0;
                }
                throw e;
            }
        }
    }

    static class CircuitOpenException extends RuntimeException {
        CircuitOpenException() { super("Circuit is OPEN — failing fast"); }
    }

    public static void main(String[] args) throws Exception {
        CircuitBreaker cb = new CircuitBreaker();
        Supplier<String> failingCall = () -> { throw new RuntimeException("Service down"); };
        Supplier<String> successCall = () -> "OK";

        for (int i = 0; i < 3; i++) {
            try { cb.execute(failingCall); } catch (Exception ignored) {}
        }
        System.out.println("State after 3 failures: " + cb.state);

        try { cb.execute(successCall); } catch (CircuitOpenException e) {
            System.out.println("Fast fail: " + e.getMessage());
        }
    }
}

