import java.util.*;
import java.util.concurrent.*;
import java.util.concurrent.atomic.*;

public class Q2 {
    static class ServiceRegistry {
        private final Map<String, List<String>> services = new ConcurrentHashMap<>();
        private final Map<String, AtomicInteger> counters = new ConcurrentHashMap<>();

        public void register(String name, String url) {
            services.computeIfAbsent(name, k -> new CopyOnWriteArrayList<>()).add(url);
            counters.putIfAbsent(name, new AtomicInteger(0));
        }

        public String discover(String name) {
            List<String> urls = services.get(name);
            if (urls == null || urls.isEmpty()) throw new RuntimeException("No instances for: " + name);
            int idx = counters.get(name).getAndIncrement() % urls.size();
            return urls.get(idx);
        }
    }

    public static void main(String[] args) {
        ServiceRegistry registry = new ServiceRegistry();
        registry.register("user-service", "http://host1:8081");
        registry.register("user-service", "http://host2:8081");
        System.out.println(registry.discover("user-service"));
        System.out.println(registry.discover("user-service"));
        System.out.println(registry.discover("user-service"));
    }
}

problems.description:
Implement event-driven communication between microservices using Spring Kafka.

```java
// Producer (Order Service):
@Service public class OrderService {
    @Autowired KafkaTemplate<String, OrderEvent> kafka;
    public Order create(OrderRequest req) {
        Order order = orderRepo.save(new Order(req));
        kafka.send("order-events", order.getId().toString(), new OrderEvent(order));
        return order;
    }
}

// Consumer (Notification Service):
@Service public class NotificationService {
    @KafkaListener(topics = "order-events", groupId = "notification-group")
    public void handleOrder(OrderEvent event) {
        emailService.sendConfirmation(event.getCustomerEmail(), event.getOrderId());
    }
}
```

**Key insight:** Async events = loose coupling. Services don't need to know about each other. Order service continues without waiting for email. Kafka retains events if notification service is down.

