import java.util.*;

public class Q3 {
    record SagaStep(String name, Runnable action, Runnable compensation) {}

    static class Saga {
        private final List<SagaStep> steps = new ArrayList<>();
        private final List<SagaStep> completed = new ArrayList<>();

        public Saga addStep(SagaStep step) { steps.add(step); return this; }

        public void execute() {
            for (SagaStep step : steps) {
                try {
                    step.action().run();
                    completed.add(step);
                } catch (Exception e) {
                    System.out.println("Step '" + step.name() + "' failed: " + e.getMessage());
                    System.out.println("Running compensations...");
                    // Compensate in reverse order
                    for (int i = completed.size() - 1; i >= 0; i--)
                        completed.get(i).compensation().run();
                    return;
                }
            }
        }
    }

    public static void main(String[] args) {
        new Saga()
            .addStep(new SagaStep("CreateOrder",
                () -> System.out.println("Order created"),
                () -> System.out.println("Order cancelled")))
            .addStep(new SagaStep("ChargePayment",
                () -> System.out.println("Payment charged"),
                () -> System.out.println("Payment refunded")))
            .addStep(new SagaStep("ReserveInventory",
                () -> { throw new RuntimeException("Out of stock"); },
                () -> System.out.println("Inventory released")))
            .execute();
    }
}
